CREATE DATABASE IF NOT EXISTS restaurante_sistema CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE restaurante_sistema;

CREATE TABLE IF NOT EXISTS clientes (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre_comercial VARCHAR(150) NOT NULL,razon_social VARCHAR(180),nit VARCHAR(50),telefono VARCHAR(40),email VARCHAR(120),direccion VARCHAR(255),estado ENUM('ACTIVO','INACTIVO','SUSPENDIDO') NOT NULL DEFAULT 'ACTIVO',fecha_registro DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,deleted_at DATETIME NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS sucursales (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,nombre VARCHAR(150) NOT NULL,codigo VARCHAR(50) NOT NULL,telefono VARCHAR(40),direccion VARCHAR(255),ciudad VARCHAR(100),zona VARCHAR(100),responsable VARCHAR(150),estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,deleted_at DATETIME NULL,UNIQUE KEY uq_sucursal_codigo(cliente_id,codigo),FOREIGN KEY(cliente_id) REFERENCES clientes(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS almacenes (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,sucursal_id BIGINT UNSIGNED NULL,nombre VARCHAR(150) NOT NULL,codigo VARCHAR(50) NOT NULL,direccion VARCHAR(255),ciudad VARCHAR(100),zona VARCHAR(100),responsable VARCHAR(150),estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,deleted_at DATETIME NULL,UNIQUE KEY uq_almacen_codigo(cliente_id,codigo),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(sucursal_id) REFERENCES sucursales(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS ubicaciones_stock (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,tipo_ubicacion ENUM('SUCURSAL','ALMACEN') NOT NULL,sucursal_id BIGINT UNSIGNED NULL,almacen_id BIGINT UNSIGNED NULL,nombre VARCHAR(150) NOT NULL,estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(sucursal_id) REFERENCES sucursales(id),FOREIGN KEY(almacen_id) REFERENCES almacenes(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS roles (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,codigo VARCHAR(60) NOT NULL UNIQUE,nombre VARCHAR(120) NOT NULL,descripcion TEXT,nivel INT NOT NULL DEFAULT 0,estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS permisos (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,codigo VARCHAR(100) NOT NULL UNIQUE,modulo VARCHAR(80) NOT NULL,accion VARCHAR(80) NOT NULL,descripcion VARCHAR(255),estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS rol_permisos (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,rol_id BIGINT UNSIGNED NOT NULL,permiso_id BIGINT UNSIGNED NOT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE KEY uq_rol_permiso(rol_id,permiso_id),FOREIGN KEY(rol_id) REFERENCES roles(id),FOREIGN KEY(permiso_id) REFERENCES permisos(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS usuarios (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,sucursal_id BIGINT UNSIGNED NULL,username VARCHAR(80) NOT NULL,password_hash VARCHAR(255) NOT NULL,nombres VARCHAR(120) NOT NULL,apellido_paterno VARCHAR(120),apellido_materno VARCHAR(120),edad INT NULL,celular VARCHAR(40),email VARCHAR(120),estado ENUM('ACTIVO','INACTIVO','BLOQUEADO') NOT NULL DEFAULT 'ACTIVO',ultimo_login_at DATETIME NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,deleted_at DATETIME NULL,UNIQUE KEY uq_usuario_cliente_username(cliente_id,username),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(sucursal_id) REFERENCES sucursales(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS usuario_roles (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,usuario_id BIGINT UNSIGNED NOT NULL,rol_id BIGINT UNSIGNED NOT NULL,alcance ENUM('CLIENTE','SUCURSAL','ALMACEN') NOT NULL DEFAULT 'CLIENTE',sucursal_id BIGINT UNSIGNED NULL,almacen_id BIGINT UNSIGNED NULL,estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(usuario_id) REFERENCES usuarios(id),FOREIGN KEY(rol_id) REFERENCES roles(id),FOREIGN KEY(sucursal_id) REFERENCES sucursales(id),FOREIGN KEY(almacen_id) REFERENCES almacenes(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS alertas (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,titulo VARCHAR(150) NOT NULL,mensaje TEXT NOT NULL,tipo_alerta ENUM('GENERAL','STOCK_BAJO','PRECIO','VENTA','SISTEMA','PROMOCION') NOT NULL DEFAULT 'GENERAL',prioridad ENUM('BAJA','MEDIA','ALTA') NOT NULL DEFAULT 'MEDIA',estado ENUM('ACTIVA','INACTIVA','VENCIDA') NOT NULL DEFAULT 'ACTIVA',fecha_inicio DATETIME NULL,fecha_fin DATETIME NULL,created_by BIGINT UNSIGNED NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,deleted_at DATETIME NULL,FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(created_by) REFERENCES usuarios(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS categorias_producto (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,categoria_padre_id BIGINT UNSIGNED NULL,nombre VARCHAR(150) NOT NULL,descripcion TEXT,estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,deleted_at DATETIME NULL,UNIQUE KEY uq_categoria_nombre(cliente_id,nombre),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(categoria_padre_id) REFERENCES categorias_producto(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS marcas (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,nombre VARCHAR(150) NOT NULL,descripcion TEXT,estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,deleted_at DATETIME NULL,UNIQUE KEY uq_marca_nombre(cliente_id,nombre),FOREIGN KEY(cliente_id) REFERENCES clientes(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS productos (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,categoria_id BIGINT UNSIGNED NOT NULL,marca_id BIGINT UNSIGNED NULL,nombre VARCHAR(180) NOT NULL,descripcion TEXT,codigo_producto VARCHAR(80) NOT NULL,codigo_barras VARCHAR(120),precio_compra DECIMAL(12,2) NULL,unidad_base VARCHAR(30) NOT NULL DEFAULT 'UNIDAD',contenido_por_caja DECIMAL(12,3),maneja_stock TINYINT(1) NOT NULL DEFAULT 1,estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,deleted_at DATETIME NULL,UNIQUE KEY uq_producto_codigo(cliente_id,codigo_producto),UNIQUE KEY uq_producto_barras(cliente_id,codigo_barras),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(categoria_id) REFERENCES categorias_producto(id),FOREIGN KEY(marca_id) REFERENCES marcas(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS producto_presentaciones (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,producto_id BIGINT UNSIGNED NOT NULL,tipo_presentacion ENUM('UNIDAD','CUARTA','MEDIA','DOCENA','CAJA') NOT NULL,nombre VARCHAR(80) NOT NULL,factor_unidad_base DECIMAL(12,3) NOT NULL DEFAULT 1,codigo_barras VARCHAR(120),estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,UNIQUE KEY uq_presentacion_producto_tipo(producto_id,tipo_presentacion),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(producto_id) REFERENCES productos(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS producto_precios (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,producto_id BIGINT UNSIGNED NOT NULL,producto_presentacion_id BIGINT UNSIGNED NOT NULL,precio_venta_estandar DECIMAL(12,2) NOT NULL,precio_minimo_venta DECIMAL(12,2) NOT NULL,moneda VARCHAR(10) NOT NULL DEFAULT 'BOB',vigente_desde DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,vigente_hasta DATETIME NULL,estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,CHECK(precio_minimo_venta<=precio_venta_estandar),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(producto_id) REFERENCES productos(id),FOREIGN KEY(producto_presentacion_id) REFERENCES producto_presentaciones(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS inventarios (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,producto_id BIGINT UNSIGNED NOT NULL,ubicacion_stock_id BIGINT UNSIGNED NOT NULL,cantidad_disponible DECIMAL(12,3) NOT NULL DEFAULT 0,cantidad_reservada DECIMAL(12,3) NOT NULL DEFAULT 0,cantidad_minima DECIMAL(12,3) NOT NULL DEFAULT 0,cantidad_maxima DECIMAL(12,3),updated_at DATETIME NULL,UNIQUE KEY uq_inventario_producto_ubicacion(cliente_id,producto_id,ubicacion_stock_id),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(producto_id) REFERENCES productos(id),FOREIGN KEY(ubicacion_stock_id) REFERENCES ubicaciones_stock(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS clientes_finales (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,nombre VARCHAR(120) NOT NULL,apellido_paterno VARCHAR(120),apellido_materno VARCHAR(120),nit_ci VARCHAR(40),celular VARCHAR(40),email VARCHAR(120),direccion VARCHAR(255),created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,deleted_at DATETIME NULL,FOREIGN KEY(cliente_id) REFERENCES clientes(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS ordenes_venta (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,sucursal_id BIGINT UNSIGNED NULL,ubicacion_stock_id BIGINT UNSIGNED NULL,vendedor_id BIGINT UNSIGNED NULL,cajero_id BIGINT UNSIGNED NULL,creado_por_usuario_id BIGINT UNSIGNED NULL,cliente_final_id BIGINT UNSIGNED NULL,codigo_orden VARCHAR(80) NOT NULL,estado ENUM('BORRADOR','ENVIADA_CAJA','EN_REVISION_CAJA','APROBADA','FACTURADA','CANCELADA') NOT NULL DEFAULT 'BORRADOR',subtotal DECIMAL(12,2) NOT NULL DEFAULT 0,descuento_total DECIMAL(12,2) NOT NULL DEFAULT 0,total_estimado DECIMAL(12,2) NOT NULL DEFAULT 0,observacion TEXT,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,UNIQUE KEY uq_orden_codigo(cliente_id,codigo_orden),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(sucursal_id) REFERENCES sucursales(id),FOREIGN KEY(ubicacion_stock_id) REFERENCES ubicaciones_stock(id),FOREIGN KEY(vendedor_id) REFERENCES usuarios(id),FOREIGN KEY(cajero_id) REFERENCES usuarios(id),FOREIGN KEY(creado_por_usuario_id) REFERENCES usuarios(id),FOREIGN KEY(cliente_final_id) REFERENCES clientes_finales(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS orden_venta_detalles (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,orden_venta_id BIGINT UNSIGNED NOT NULL,producto_id BIGINT UNSIGNED NOT NULL,producto_presentacion_id BIGINT UNSIGNED NOT NULL,cantidad DECIMAL(12,3) NOT NULL,precio_estandar DECIMAL(12,2) NOT NULL,precio_minimo_venta DECIMAL(12,2) NOT NULL,precio_unitario DECIMAL(12,2) NOT NULL,descuento DECIMAL(12,2) NOT NULL DEFAULT 0,subtotal DECIMAL(12,2) NOT NULL,observacion TEXT,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,CHECK(precio_unitario>=precio_minimo_venta),CHECK(precio_unitario<=precio_estandar),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(orden_venta_id) REFERENCES ordenes_venta(id),FOREIGN KEY(producto_id) REFERENCES productos(id),FOREIGN KEY(producto_presentacion_id) REFERENCES producto_presentaciones(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS ventas (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,sucursal_id BIGINT UNSIGNED NULL,ubicacion_stock_id BIGINT UNSIGNED NULL,orden_venta_id BIGINT UNSIGNED NULL,cliente_final_id BIGINT UNSIGNED NULL,cajero_id BIGINT UNSIGNED NULL,vendedor_id BIGINT UNSIGNED NULL,numero_venta VARCHAR(80) NOT NULL,fecha_venta DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,subtotal DECIMAL(12,2) NOT NULL DEFAULT 0,descuento_total DECIMAL(12,2) NOT NULL DEFAULT 0,total DECIMAL(12,2) NOT NULL DEFAULT 0,estado ENUM('PENDIENTE','PAGADA','ANULADA','DEVUELTA_PARCIAL','DEVUELTA_TOTAL') NOT NULL DEFAULT 'PAGADA',idempotency_key VARCHAR(120) NULL,observacion TEXT,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,UNIQUE KEY uq_venta_numero(cliente_id,numero_venta),UNIQUE KEY uq_venta_idempotencia(cliente_id,idempotency_key),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(sucursal_id) REFERENCES sucursales(id),FOREIGN KEY(ubicacion_stock_id) REFERENCES ubicaciones_stock(id),FOREIGN KEY(orden_venta_id) REFERENCES ordenes_venta(id),FOREIGN KEY(cliente_final_id) REFERENCES clientes_finales(id),FOREIGN KEY(cajero_id) REFERENCES usuarios(id),FOREIGN KEY(vendedor_id) REFERENCES usuarios(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS venta_detalles (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,venta_id BIGINT UNSIGNED NOT NULL,producto_id BIGINT UNSIGNED NOT NULL,producto_presentacion_id BIGINT UNSIGNED NOT NULL,cantidad DECIMAL(12,3) NOT NULL,precio_estandar DECIMAL(12,2) NOT NULL,precio_minimo_venta DECIMAL(12,2) NOT NULL,precio_unitario DECIMAL(12,2) NOT NULL,descuento DECIMAL(12,2) NOT NULL DEFAULT 0,subtotal DECIMAL(12,2) NOT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,CHECK(precio_unitario>=precio_minimo_venta),CHECK(precio_unitario<=precio_estandar),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(venta_id) REFERENCES ventas(id),FOREIGN KEY(producto_id) REFERENCES productos(id),FOREIGN KEY(producto_presentacion_id) REFERENCES producto_presentaciones(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS venta_pagos (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,venta_id BIGINT UNSIGNED NOT NULL,metodo_pago ENUM('EFECTIVO','QR','TARJETA','TRANSFERENCIA','MIXTO') NOT NULL,monto DECIMAL(12,2) NOT NULL,referencia VARCHAR(120),estado ENUM('PENDIENTE','CONFIRMADO','ANULADO') NOT NULL DEFAULT 'CONFIRMADO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(venta_id) REFERENCES ventas(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS inventario_movimientos (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,producto_id BIGINT UNSIGNED NOT NULL,ubicacion_origen_id BIGINT UNSIGNED NULL,ubicacion_destino_id BIGINT UNSIGNED NULL,tipo_movimiento ENUM('ENTRADA','SALIDA','TRASPASO','VENTA','AJUSTE_POSITIVO','AJUSTE_NEGATIVO','DEVOLUCION') NOT NULL,cantidad DECIMAL(12,3) NOT NULL,costo_unitario DECIMAL(12,2) NULL,referencia_tipo VARCHAR(80),referencia_id BIGINT UNSIGNED NULL,usuario_id BIGINT UNSIGNED NULL,observacion TEXT,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(producto_id) REFERENCES productos(id),FOREIGN KEY(ubicacion_origen_id) REFERENCES ubicaciones_stock(id),FOREIGN KEY(ubicacion_destino_id) REFERENCES ubicaciones_stock(id),FOREIGN KEY(usuario_id) REFERENCES usuarios(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS proveedores (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,nombre VARCHAR(180) NOT NULL,nit VARCHAR(60),telefono VARCHAR(40),email VARCHAR(120),direccion VARCHAR(255),contacto VARCHAR(150),estado ENUM('ACTIVO','INACTIVO') NOT NULL DEFAULT 'ACTIVO',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,deleted_at DATETIME NULL,FOREIGN KEY(cliente_id) REFERENCES clientes(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS compras (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,proveedor_id BIGINT UNSIGNED NULL,almacen_id BIGINT UNSIGNED NULL,usuario_id BIGINT UNSIGNED NULL,numero_documento VARCHAR(100),fecha_compra DATETIME NULL,subtotal DECIMAL(12,2) NOT NULL DEFAULT 0,descuento DECIMAL(12,2) NOT NULL DEFAULT 0,total DECIMAL(12,2) NOT NULL DEFAULT 0,estado ENUM('BORRADOR','CONFIRMADA','ANULADA') NOT NULL DEFAULT 'BORRADOR',observacion TEXT,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL,FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(proveedor_id) REFERENCES proveedores(id),FOREIGN KEY(almacen_id) REFERENCES almacenes(id),FOREIGN KEY(usuario_id) REFERENCES usuarios(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS auditoria_eventos (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NULL,usuario_id BIGINT UNSIGNED NULL,modulo VARCHAR(80) NOT NULL,accion VARCHAR(120) NOT NULL,tabla_afectada VARCHAR(120),registro_id BIGINT UNSIGNED NULL,valor_anterior_json JSON NULL,valor_nuevo_json JSON NULL,ip_address VARCHAR(80),user_agent VARCHAR(255),created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,INDEX idx_auditoria_cliente_fecha(cliente_id,created_at),FOREIGN KEY(cliente_id) REFERENCES clientes(id),FOREIGN KEY(usuario_id) REFERENCES usuarios(id)) ENGINE=InnoDB;
